from fractions import Fraction

def find_peaks(counts, threshold=0.1):
    total_counts = sum(counts.values())
    peaks = set()
    for bitstring, count in counts.items():
        if count / total_counts > threshold:
            peaks.add(bitstring)
    return peaks

def continued_fraction_postprocessing(peaks, expected_period):
    for peak in peaks:
        for p in range(1, expected_period):
            if Fraction(int(peak, 2), p) == Fraction(expected_period, p):
                if p == expected_period:
                    return True
    return False

